changeSet.sql:
-- GIN indexes for JSONB columns
CREATE INDEX IF NOT EXISTS idx_qm_results_cql_result_gin ON quality_measure_results USING GIN (cql_result);
CREATE INDEX IF NOT EXISTS idx_custom_measures_value_sets_gin ON custom_measures USING GIN (value_sets);
CREATE INDEX IF NOT EXISTS idx_risk_assessments_risk_factors_gin ON risk_assessments USING GIN (risk_factors);
CREATE INDEX IF NOT EXISTS idx_risk_assessments_predicted_outcomes_gin ON risk_assessments USING GIN (predicted_outcomes);
CREATE INDEX IF NOT EXISTS idx_risk_assessments_recommendations_gin ON risk_assessments USING GIN (recommendations);

rollback.sql:
DROP INDEX IF EXISTS idx_qm_results_cql_result_gin;
DROP INDEX IF EXISTS idx_custom_measures_value_sets_gin;
DROP INDEX IF EXISTS idx_risk_assessments_risk_factors_gin;
DROP INDEX IF EXISTS idx_risk_assessments_predicted_outcomes_gin;
DROP INDEX IF EXISTS idx_risk_assessments_recommendations_gin;
